export const customFieldRelations = relations(CustomField, ({ one, many }) => ({
  organization: one(Organization, {
    fields: [CustomField.organizationId],
    references: [Organization.id],
  }),
  entityDefinition: one(EntityDefinition, {
    fields: [CustomField.entityDefinitionId],
    references: [EntityDefinition.id],
  }),
  fieldValues: many(CustomFieldValue),
  // New typed field values (FieldValue table)
  typedFieldValues: many(FieldValue),
}))

export const customFieldValueRelations = relations(CustomFieldValue, ({ one }) => ({
  field: one(CustomField, {
    fields: [CustomFieldValue.fieldId],
    references: [CustomField.id],
  }),
  // Relation to EntityInstance for custom entity values
  // entityId is polymorphic but this enables the EntityInstance.values relation
  entityInstance: one(EntityInstance, {
    fields: [CustomFieldValue.entityId],
    references: [EntityInstance.id],
  }),
}))

/**
 * FieldValue relations - typed field value storage
 * This is the new storage format replacing CustomFieldValue JSONB
 */
export const fieldValueRelations = relations(FieldValue, ({ one }) => ({
  field: one(CustomField, {
    fields: [FieldValue.fieldId],
    references: [CustomField.id],
  }),
  organization: one(Organization, {
    fields: [FieldValue.organizationId],
    references: [Organization.id],
  }),
  // entityId is polymorphic (Contact, Ticket, EntityInstance, etc.)
  // We define explicit relation to EntityInstance for custom entities
  entityInstance: one(EntityInstance, {
    fields: [FieldValue.entityId],
    references: [EntityInstance.id],
  }),
}))

export const entityDefinitionRelations = relations(EntityDefinition, ({ one, many }) => ({
  organization: one(Organization, {
    fields: [EntityDefinition.organizationId],
    references: [Organization.id],
  }),
  customFields: many(CustomField),
  instances: many(EntityInstance),
  // Display field relations
  primaryDisplayField: one(CustomField, {
    fields: [EntityDefinition.primaryDisplayFieldId],
    references: [CustomField.id],
    relationName: 'entityDefinition_primaryDisplayFieldId_customField_id',
  }),
  secondaryDisplayField: one(CustomField, {
    fields: [EntityDefinition.secondaryDisplayFieldId],
    references: [CustomField.id],
    relationName: 'entityDefinition_secondaryDisplayFieldId_customField_id',
  }),
  avatarField: one(CustomField, {
    fields: [EntityDefinition.avatarFieldId],
    references: [CustomField.id],
    relationName: 'entityDefinition_avatarFieldId_customField_id',
  }),
}))

export const entityInstanceRelations = relations(EntityInstance, ({ one, many }) => ({
  entityDefinition: one(EntityDefinition, {
    fields: [EntityInstance.entityDefinitionId],
    references: [EntityDefinition.id],
  }),
  organization: one(Organization, {
    fields: [EntityInstance.organizationId],
    references: [Organization.id],
  }),
  createdBy: one(User, {
    fields: [EntityInstance.createdById],
    references: [User.id],
  }),
  // Custom field values for this instance (legacy JSONB)
  values: many(CustomFieldValue),
  // New typed field values
  typedValues: many(FieldValue),
  // Group members (when this instance IS a group with resourceType: 'entity_group')
  groupMembers: many(EntityGroupMember),
  // Group permissions (when this instance IS a group with resourceType: 'entity_group')
  groupPermissions: many(EntityGroupPermission),
}))

